        var distanceY = e.pageY - positionDiv.top;
        //alert(distanceX)
        // alert(positionDiv.left);

        jquery(document).mousemove(function(e) {
            var x = e.clientX - distanceX;
            var y = e.clientY - distanceY;

            if (x < 0) {
                x = 0;
            } else if (x > window.innerWidth - jquery('.tooldrag').outerWidth(true)) {
                x = window.innerWidth - jquery('.tooldrag').outerWidth(true);
            }

            if (y < 0) {
                y = 0;
            } else if (y > window.innerHeight - jquery('.tooldrag').outerHeight(true)) {
                y = window.innerHeight - jquery('.tooldrag').outerHeight(true);
            }

