            } catch(e){

            }
            // set the new width of the wrapperToolkit
        }
    });

    window.addEventListener('mouseup', e => {
        // when the mouse is released, stop resizing
        mousedown = false;
    });
    setInterval(function() { //时刻监测相应元素是否存在(防止出现如百度一样元素消失重写body的情况)，如果不存在，添加进来
