                let size = screen.getPrimaryDisplay().workAreaSize;
                let width = parseInt(size.width);
                let height = parseInt(size.height * 0.6);
                window.setBounds({
                    x: 0,
                    y: size.height * 0.4,
                    height: height,
                    width: width,
                });
