                let elementInfo = {iframe: parameters.iframe, xpath: xpath, id: -1};
                //用于跳转到元素位置
                let element = await findElementAcrossAllWindows(elementInfo);
            } else if (option == 3) {
                let params = parameters.params; //所有的提取数据参数
                let param = params[0];
