                if (param.relative) {
                    let parent_node = JSON.parse(msg.message.parentNode);
                    let parent_xpath = parent_node.parameters.xpath;
                    if (parent_node.parameters.loopType == 2) {
                        parent_xpath = parent_node.parameters.pathList
                            .split("\n")[0]
