                        // 创建一个新的正则表达式来匹配JS语句
                        let pattern = /JS\("(.+?)"\)/gi;

                        // 找出所有的匹配项
                        let matches = [...keyInfo.matchAll(pattern)];

                        // 处理每一个匹配项
                        for (let match of matches) {
                            // 执行 JS 代码并等待结果
                            let jsReplacedText = await execute_js(match[1], null, 0);
                            // 替换匹配到的 JS 语句
                            keyInfo = keyInfo.replace(match[0], jsReplacedText.toString());
