    } catch (e) {
        showError(LANG("试运行功能只能在任务设计阶段，Chrome浏览器打开时使用！", "The trial run function can only be used when designing tasks and opening in Chrome browser!"));
    }
    e.stopPropagation(); //防止冒泡
}

