function copyFolderSync(source, target) {
    try {
        // 如果目标文件夹已存在，则先删除
        if (fs.existsSync(target)) {
            fs.removeSync(target);
        }

        // 复制文件夹
        fs.copySync(source, target);
        console.log('文件夹复制完成！');
    } catch (err) {
        console.error('复制文件夹时出错:', err);
    }
}

